using System;
using System.Collections.Generic;
using System.Linq;
using BankInsight.API.DTOs;
using BankInsight.API.Security;

namespace BankInsight.API.Services;

public record ReportCatalogDefinition(
    string ReportCode,
    string ReportName,
    string Category,
    string SubCategory,
    string Description,
    string DataSource,
    IReadOnlyList<string> RequiredPermissions,
    IReadOnlyList<string> ExportFormats,
    IReadOnlyList<string> ApplicableInstitutionTypes,
    IReadOnlyList<ReportParameterSchemaDTO> ParameterSchema,
    IReadOnlyList<string> DefaultColumns,
    string DefaultSort,
    bool IsRegulatory,
    bool RequiresApprovalBeforeFinalExport,
    bool SupportsBranchScope,
    bool SupportsHeadOfficeScope,
    string Version,
    DateTime? EffectiveFrom = null,
    DateTime? EffectiveTo = null,
    bool IsActive = true);

public interface IReportCatalogRegistry
{
    IReadOnlyList<ReportCatalogDefinition> GetAll();
    ReportCatalogDefinition? GetByCode(string reportCode);
}

public class ReportCatalogRegistry : IReportCatalogRegistry
{
    private static readonly IReadOnlyList<ReportCatalogDefinition> Definitions = BuildDefinitions();

    public IReadOnlyList<ReportCatalogDefinition> GetAll() => Definitions;

    public ReportCatalogDefinition? GetByCode(string reportCode) =>
        Definitions.FirstOrDefault(item => string.Equals(item.ReportCode, reportCode, StringComparison.OrdinalIgnoreCase));

