    private static ReportCatalogDefinition Def(
        string code,
        string name,
        string category,
        string subCategory,
        string description,
        string dataSource,
        IReadOnlyList<string> permissions,
        IReadOnlyList<string> exportFormats,
        IReadOnlyList<string> institutionTypes,
        IReadOnlyList<ReportParameterSchemaDTO> parameters,
        IReadOnlyList<string> defaultColumns,
        string defaultSort,
        bool isRegulatory,
        bool requiresApproval,
        bool branchScope,
        bool headOfficeScope) =>
        new(code, name, category, subCategory, description, dataSource, permissions, exportFormats, institutionTypes, parameters, defaultColumns, defaultSort, isRegulatory, requiresApproval, branchScope, headOfficeScope, "1.0", DateTime.UtcNow.Date);

    private static ReportParameterSchemaDTO P(string name, string label, string type, bool required, string? defaultValue = null, string? placeholder = null, IEnumerable<string>? options = null) =>
        new()
        {
            Name = name,
            Label = label,
            Type = type,
            Required = required,
            DefaultValue = defaultValue,
            Placeholder = placeholder,
            Options = options?.ToList() ?? new List<string>()
        };
}

